 32→      {PRODUCTS.map(p => (
 33→        <Pressable
 34→          key={p}
 35→          onPress={() => onSelect(p)}
 36→          style={{
 37→            paddingHorizontal: 16,
 38→            paddingVertical: 8,
 39→            borderRadius: 20,
 40→            backgroundColor: selected === p ? '#6B2FBE' : '#E8E0F0',
 41→          }}
 42→        >
